searchData={"items":[{"type":"module","doc":"50 years of Pure Type Systems\n\nAUTOMATH (c) 1968, Nicolaas Govert de Bruijn\nCalculus of Construction (c) 1988, Thierry Coquand\nMorte (c) 2014, Gabriella Gonzalez\nHenk (c) 2018, Namdak Tonpa\n\nCoC Syntax:\n\n*₁₀₁        -- 101-th Universe\n[x : A] Exp -- Universal Quantifier\n(x : A) Exp -- Lambda\nM N         -- Application\nL₁          -- Variable with de Bruijn index 1","title":"AUTOMATH","ref":"AUTOMATH.html"},{"type":"function","doc":"","title":"AUTOMATH.atmb/1","ref":"AUTOMATH.html#atmb/1"},{"type":"function","doc":"","title":"AUTOMATH.bin/1","ref":"AUTOMATH.html#bin/1"},{"type":"function","doc":"","title":"AUTOMATH.ext/1","ref":"AUTOMATH.html#ext/1"},{"type":"function","doc":"","title":"AUTOMATH.ilst/1","ref":"AUTOMATH.html#ilst/1"},{"type":"function","doc":"","title":"AUTOMATH.lbin/1","ref":"AUTOMATH.html#lbin/1"},{"type":"function","doc":"","title":"AUTOMATH.lstb/1","ref":"AUTOMATH.html#lstb/1"},{"type":"function","doc":"","title":"AUTOMATH.lsti/1","ref":"AUTOMATH.html#lsti/1"},{"type":"function","doc":"","title":"AUTOMATH.name/2","ref":"AUTOMATH.html#name/2"},{"type":"function","doc":"","title":"AUTOMATH.prn/1","ref":"AUTOMATH.html#prn/1"},{"type":"function","doc":"","title":"AUTOMATH.sub/1","ref":"AUTOMATH.html#sub/1"},{"type":"function","doc":"","title":"AUTOMATH.utf8/1","ref":"AUTOMATH.html#utf8/1"},{"type":"module","doc":"","title":"Henk","ref":"Henk.html"},{"type":"function","doc":"Callback implementation for  Application.start/2 .","title":"Henk.start/2","ref":"Henk.html#start/2"}],"proglang":"elixir","content_type":"text/markdown","producer":{"name":"ex_doc","version":"0.40.1"}}